rpm_data = data_open_air["rpm_data"]
time_data = data_open_air["time_data"]

# step starts after 10 samples so start_idx must be 10
start_idx = 10
duty_step_size = 0.5

t = np.array(time_data[start_idx:], dtype=float)
t = t - t[0]  # shift time values for the step to start at time 0

y = np.array(rpm_data[start_idx:], dtype=float)

def pt1(t, A, T):
    return A * (1 - np.exp(-t / T))

popt, _ = curve_fit(pt1, t, y, p0=[y[-1] - y[0], 1e6])
A, T = popt

print(f"K = {A/duty_step_size}")
print(f"T = {T}")

y_fit = pt1(t, A*0.97, 1008186)

plt.figure(figsize=(10,5))
plt.title("Open-Air Fan Step Response Numerical Fitting")
plt.plot(t, y, label="Measured")
plt.plot(t, y_fit, linewidth=2,
         label=f"PT1 fit (K={A/duty_step_size:.2f} rpm, T={T:.0f} µs)")
plt.grid(True)
plt.legend()
plt.show()